                    positions[val] = []
                counts[val] += 1
                positions[val].append((r, c))

    barrier_val = max(counts, key=counts.get)
    filler_vals = [v for v in counts if v != barrier_val]

    barrier_pos = positions[barrier_val]

    # Check orientation of the barrier
    is_vertical = all(p[1] == barrier_pos[0][1] for p in barrier_pos)
    is_horizontal = all(p[0] == barrier_pos[0][0] for p in barrier_pos)

    if is_vertical:
        # Fill horizontally
        barrier_col = barrier_pos[0][1]
        for val in filler_vals:
            for r, c in positions[val]:
                start_col = min(c, barrier_col)
                end_col = max(c, barrier_col)
                for j in range(start_col, end_col + 1):
                    if grid[r][j] == 0:
                        output_grid[r][j] = val
