    sources = []
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] != 0 and grid[r][c] != 5:
                sources.append(((r, c), grid[r][c]))

    for pos, val in sources:
        r, c = pos
        # Look right
        for c2 in range(c + 1, cols):
            if grid[r][c2] == 5:
                for fill_c in range(c + 1, c2):
                    if grid[r][fill_c] == 0:
                        output_grid[r][fill_c] = val
                break
        # Look left
        for c2 in range(c - 1, -1, -1):
            if grid[r][c2] == 5:
                for fill_c in range(c2 + 1, c):
                    if grid[r][fill_c] == 0:
                        output_grid[r][fill_c] = val
                break
        # Look down
        for r2 in range(r + 1, rows):
            if grid[r2][c] == 5:
                for fill_r in range(r + 1, r2):
                    if grid[fill_r][c] == 0:
                        output_grid[fill_r][c] = val
                break
        # Look up
        for r2 in range(r - 1, -1, -1):
            if grid[r2][c] == 5:
                for fill_r in range(r2 + 1, r):
                    if grid[fill_r][c] == 0:
